def _databricks_metric_view_to_nested(
    databricks_metric_view: DatabricksMetricView,
) -> DatabricksMetricViewNested:
    """Convert flat DatabricksMetricView to nested format."""
    attrs = DatabricksMetricViewAttributes()
    _populate_databricks_metric_view_attrs(attrs, databricks_metric_view)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        databricks_metric_view,
        _DATABRICKS_METRIC_VIEW_REL_FIELDS,
        DatabricksMetricViewRelationshipAttributes,
    )
    return DatabricksMetricViewNested(
        guid=databricks_metric_view.guid,
        type_name=databricks_metric_view.type_name,
        status=databricks_metric_view.status,
        version=databricks_metric_view.version,
        create_time=databricks_metric_view.create_time,
        update_time=databricks_metric_view.update_time,
        created_by=databricks_metric_view.created_by,
        updated_by=databricks_metric_view.updated_by,
        classifications=databricks_metric_view.classifications,
        classification_names=databricks_metric_view.classification_names,
        meanings=databricks_metric_view.meanings,
        labels=databricks_metric_view.labels,
        business_attributes=databricks_metric_view.business_attributes,
        custom_attributes=databricks_metric_view.custom_attributes,
        pending_tasks=databricks_metric_view.pending_tasks,
        proxy=databricks_metric_view.proxy,
        is_incomplete=databricks_metric_view.is_incomplete,
        provenance_type=databricks_metric_view.provenance_type,
        home_id=databricks_metric_view.home_id,
        depth=databricks_metric_view.depth,
        immediate_upstream=databricks_metric_view.immediate_upstream,
        immediate_downstream=databricks_metric_view.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _databricks_metric_view_from_nested(
    nested: DatabricksMetricViewNested,
) -> DatabricksMetricView:
    """Convert nested format to flat DatabricksMetricView."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DatabricksMetricViewAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DATABRICKS_METRIC_VIEW_REL_FIELDS,
        DatabricksMetricViewRelationshipAttributes,
    )
    return DatabricksMetricView(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_databricks_metric_view_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _databricks_metric_view_to_nested_bytes(
    databricks_metric_view: DatabricksMetricView, serde: Serde
) -> bytes:
    """Convert flat DatabricksMetricView to nested JSON bytes."""
    return serde.encode(_databricks_metric_view_to_nested(databricks_metric_view))


def _databricks_metric_view_from_nested_bytes(
    data: bytes, serde: Serde
) -> DatabricksMetricView:
    """Convert nested JSON bytes to flat DatabricksMetricView."""
    nested = serde.decode(data, DatabricksMetricViewNested)
    return _databricks_metric_view_from_nested(nested)


